import React, { Component } from 'react'
import { Carousel,Flex,Grid } from 'antd-mobile'
import axios from 'axios';
// 引入样式
import './index.css'
// 引入图片
import nav1 from '../../assets/images/nav-1.png'
import nav2 from '../../assets/images/nav-2.png'
import nav3 from '../../assets/images/nav-3.png'
import nav4 from '../../assets/images/nav-4.png'
// nav数据
const navs = [
  {
    id:1,
    img:nav1,
    title:'整租',
    path:'/home/list'
  },
  {
    id:2,
    img:nav2,
    title:'合租',
    path:'/home/list'
  },
  {
    id:3,
    img:nav3,
    title:'地图找房',
    path:'/map'
  },
  {
    id:4,
    img:nav4,
    title:'去出租',
    path:'/rent'
  },
]

// 
const data = Array.from(new Array(9)).map((_val, i) => ({
  icon: 'https://gw.alipayobjects.com/zos/rmsportal/nywPmnTAvTmLusPxHPSu.png',
  text: `name${i}`,
}));

const data1 = Array.from(new Array(9)).map(() => ({
  icon: 'https://gw.alipayobjects.com/zos/rmsportal/WXoqXTHrSnRcUwEaQgXJ.png',
}));


export default class Index extends Component {
  state = {
    // 轮播图
    swipers:[],
    isSwiperLoading: false,
    // 租房小组
    groups :[],
  }
  // 轮播图接口
  async getSwipers() {
    const res = await axios.get('http://localhost:8080/home/swiper')
    const {body} = res.data
    this.setState({
      swipers:body,
      isSwiperLoading: true
    })
  }
  // 租房小组接口
  async getGroups() {
    const res = await axios.get('http://localhost:8080/home/groups?area=AREA%7C88cff55c-aaa4-e2e0')
    const {body} = res.data
  }
  componentDidMount() {
    // 播放轮播图
    this.getSwipers()
    // 租房小组
    this.getGroups()
  }
  // 渲染轮播图结构
  renderSwipers() {
    return this.state.swipers.map(item => (
      <a
        key={item.id}
        href="#"
        style={{ display: 'inline-block', width: '100%', height: 212 }}
      >
        <img
          src={`http://localhost:8080${item.imgSrc}`}
          alt=""
          style={{ width: '100%', verticalAlign: 'top' }}
        />
      </a>
    ))
  }
  // 渲染nav结构
  renderNavs() {
    return navs.map(item => (
      <Flex.Item key={item.id} onClick={() => this.props.history.push(item.path)}>
        <img src={item.img} />
        <h2>{item.title}</h2>
      </Flex.Item>
    ))
    
  }
  // 渲染租房小组结构
  getGroups() {

  }
  
  render() {
    return (
      <div className='index'>
        {/* 轮播图 */}
        <div className='swiper'>
          {
            this.state.isSwiperLoading ?
            (<Carousel autoplay infinite>
              {this.renderSwipers()}
            </Carousel>) : ('')
          }
        </div>
        {/* 导航 */}
        <Flex className='nav'>
          {this.renderNavs()}
        </Flex>
        {/* 租房小组 */}
          <div className='group'>
            <h3 className='title'>租房小组<span className='more'>更多</span></h3>
            <div className="sub-title">Always square grid item </div>
      <Grid data={data} activeStyle={false} />

      <div className="sub-title">Grid item adjust accroiding to img size </div>
      <Grid data={data} square={false} className="not-square-grid" />

      <div className="sub-title">ColumnNum=3 </div>
      <Grid data={data} columnNum={3} />

      <div className="sub-title">No border</div>
      <Grid data={data} hasLine={false} />

      <div className="sub-title">Carousel</div>
      <Grid data={data} isCarousel onClick={_el => console.log(_el)} />

      <div className="sub-title">Custom content</div>
      <Grid data={data1}
        columnNum={3}
        renderItem={dataItem => (
          <div style={{ padding: '12.5px' }}>
            <img src={dataItem.icon} style={{ width: '75px', height: '75px' }} alt="" />
            <div style={{ color: '#888', fontSize: '14px', marginTop: '12px' }}>
              <span>I am title..</span>
            </div>
          </div>
        )}
      />
      <div className="sub-title">Custom GridCell Style</div>
      <Grid data={data1} columnNum={3} itemStyle={{ height: '150px', background: 'rgba(0,0,0,.05)' }} />
          </div>
      </div>
    )
  }
}
